466	function formatCategoryGraphicsMatrixCell(
467	  rows: PlanCategoryGraphicRow[] | undefined,
468	  key: PlanCategoryGraphicCategoryKey,
469	): string {
470	  const r = rows?.find((x) => x.categoryKey === key);
471	  if (!r) return 'inherit';
472	  const parts: string[] = [];
473	  if (r.lineWeightFactor != null && Number.isFinite(r.lineWeightFactor)) {
474	    parts.push(`f=${r.lineWeightFactor}`);
475	  }
476	  if (r.linePatternToken) {
477	    parts.push(`pat=${r.linePatternToken}`);
478	  }
479	  return parts.length ? parts.join(' ') : 'inherit';
480	}
