491	  elementsById: Record<string, Element>,
492	  planViewId: string,
493	): string {
494	  const g = resolvePlanGraphicHints(elementsById, planViewId);
495	  const a = resolvePlanAnnotationHints(elementsById, planViewId);
496	  const pres = resolvePlanViewDisplay(elementsById, planViewId, undefined, 'default').presentation;
497	
498	  const d = g?.detailLevel ?? 'medium';
499	  const fill = g?.roomFillOpacityScale ?? 1;
500	  const oSt = resolvePlanTagStyleLane(elementsById, planViewId, 'opening');
501	  const rSt = resolvePlanTagStyleLane(elementsById, planViewId, 'room');
502	  const oAbbrev =
503	    oSt.resolvedStyleId === BUILTIN_PLAN_TAG_OPENING_ID ? 'builtin' : oSt.resolvedStyleId;
504	  const rAbbrev =
505	    rSt.resolvedStyleId === BUILTIN_PLAN_TAG_ROOM_ID ? 'builtin' : rSt.resolvedStyleId;
506	  const cat = resolvePlanCategoryGraphics(elementsById, planViewId);
507	  const catBit =
508	    cat == null
509	      ? ''
510	      : ` · catWall f=${cat.wall.lineWeightFactor} pat=${cat.wall.linePatternToken} · catGrid pat=${cat.grid_line.linePatternToken}`;
511	  return `pres ${formatPlanPresentationStored(pres)} · ${d} · fill ${fill} · tags ${annotationTriEffective(a.openingTagsVisible)}/${annotationTriEffective(a.roomLabelsVisible)} · tagStyles o=${oAbbrev} r=${rAbbrev}${catBit}`;
512	}
