256	            style={{ letterSpacing: 'var(--text-eyebrow-tracking)' }}
257	          >
258	            Quick actions
259	          </div>
260	          <ul className="flex flex-col gap-1">
261	            {actions.map((a) => {
262	              const inner = (
263	                <>
264	                  <span>{a.label}</span>
265	                  <kbd className="rounded-sm bg-background px-1.5 py-0.5 font-mono text-[11px] text-muted">
266	                    {a.hotkey}
267	                  </kbd>
