300	function EmptyTab({ message }: { message: string }): JSX.Element {
301	  return <div className="px-1 py-2 text-xs text-muted">{message}</div>;
302	}
303	
304	/* ────────────────────────────────────────────────────────────────────── */
305	/* Numeric expression evaluator — §13.3                                    */
306	/* ────────────────────────────────────────────────────────────────────── */
307	
308	/**
309	 * Evaluate a §13.3 numeric expression. Supports `+`, `-`, `*`, `/`,
310	 * parentheses, and decimal numbers. Returns `null` for invalid input
311	 * so callers can keep the prior value and surface an error inline.
312	 */
313	export function evaluateExpression(raw: string): number | null {
314	  const trimmed = raw.trim();
315	  if (!trimmed) return null;
316	  if (!/^[\d+\-*/().\s]+$/.test(trimmed)) return null;
317	  try {
318	    // eslint-disable-next-line @typescript-eslint/no-implied-eval
319	    const value = Function(`'use strict'; return (${trimmed});`)();
320	    return Number.isFinite(value) ? Number(value) : null;
321	  } catch {
322	    return null;
323	  }
324	}
325	
326	const UNIT_CYCLE = ['mm', 'cm', 'm'] as const;
327	export type LengthUnit = (typeof UNIT_CYCLE)[number];
328	
329	function unitToMm(value: number, unit: LengthUnit): number {
330	  if (unit === 'mm') return value;
331	  if (unit === 'cm') return value * 10;
332	  return value * 1000;
333	}
334	
335	function mmToUnit(valueMm: number, unit: LengthUnit): number {
336	  if (unit === 'mm') return valueMm;
337	  if (unit === 'cm') return valueMm / 10;
338	  return valueMm / 1000;
339	}
340	
341	export interface NumericFieldProps {
342	  label: string;
343	  valueMm: number;
344	  onCommitMm: (next: number) => void;
345	  unit?: LengthUnit;
346	  step?: number;
347	  ariaLabel?: string;
348	}
349	
350	/** Numeric field with mm-canonical state but human-friendly unit chip.
351	 * On commit (Enter or blur) the input is evaluated as an expression. */
352	export function NumericField({
353	  label,
354	  valueMm,
355	  onCommitMm,
356	  unit: initialUnit = 'mm',
357	  step = 1,
358	  ariaLabel,
359	}: NumericFieldProps): JSX.Element {
360	  const [unit, setUnit] = useState<LengthUnit>(initialUnit);
361	  const [draft, setDraft] = useState<string>(() => formatForUnit(valueMm, initialUnit));
362	  const [error, setError] = useState<boolean>(false);
363	
364	  useEffect(() => {
365	    setDraft(formatForUnit(valueMm, unit));
366	    setError(false);
367	  }, [unit, valueMm]);
368	
369	  const cycleUnit = useCallback(() => {
370	    const idx = UNIT_CYCLE.indexOf(unit);
371	    setUnit(UNIT_CYCLE[(idx + 1) % UNIT_CYCLE.length]);
372	  }, [unit]);
373	
374	  const commit = useCallback(
375	    (raw: string) => {
376	      const evaluated = evaluateExpression(raw);
377	      if (evaluated === null) {
378	        setError(true);
379	        return;
380	      }
381	      onCommitMm(unitToMm(evaluated, unit));
382	    },
383	    [onCommitMm, unit],
384	  );
385	
386	  const handleSubmit = (e: FormEvent<HTMLFormElement>): void => {
387	    e.preventDefault();
388	    commit(draft);
389	  };
390	
391	  const handleChange = (e: ChangeEvent<HTMLInputElement>): void => {
392	    setDraft(e.target.value);
393	    if (error) setError(false);
394	  };
395	
396	  return (
397	    <form onSubmit={handleSubmit} className="flex flex-col gap-1">
398	      <label className="text-xs text-muted">{label}</label>
399	      <div
400	        className={[
401	          'flex items-center gap-1 rounded-md border bg-background px-2 py-1 text-sm focus-within:ring-2 focus-within:ring-offset-0',
402	          error ? 'border-danger' : 'border-border',
403	        ].join(' ')}
404	      >
405	        <input
406	          type="text"
407	          inputMode="decimal"
408	          value={draft}
409	          aria-label={ariaLabel ?? label}
410	          aria-invalid={error}
411	          step={step}
412	          onChange={handleChange}
413	          onBlur={() => commit(draft)}
414	          className="flex-1 bg-transparent text-foreground outline-none"
415	        />
416	        <button
417	          type="button"
418	          onClick={cycleUnit}
419	          aria-label={`Cycle units (current: ${unit})`}
420	          className="rounded-sm border border-border px-1.5 text-xs text-muted hover:bg-surface-strong"
421	        >
422	          {unit}
423	        </button>
424	      </div>
425	    </form>
426	  );
427	}
428	
429	function formatForUnit(valueMm: number, unit: LengthUnit): string {
430	  const v = mmToUnit(valueMm, unit);
431	  if (Number.isInteger(v)) return v.toString();
432	  return v.toFixed(unit === 'mm' ? 0 : unit === 'cm' ? 1 : 3);
433	}
434	
435	export const InspectorStyle: CSSProperties = {
436	  fontSize: 'var(--text-sm)',
437	};
438

