13	/**
14	 * StatusBar — spec §17.
15	 *
16	 * 28 px tall surface bar, bottom-of-shell. Shows clusters from left to
17	 * right: active level, current tool, snap mode group, grid toggle, model
18	 * coordinates, undo depth, ws connection, save state.
19	 *
20	 * - Coordinates use `aria-live="polite"` so screen-readers can announce
21	 *   changes without interrupting.
22	 * - The save-state pill uses `aria-live="polite"` too.
23	 * - Errors / red-alert states (offline, save failed) use
24	 *   `aria-live="assertive"`.
25	 * - Every cluster has a tooltip via `title` and a hotkey hint where the
26	 *   spec specifies one (`F3` for snap cycle, `F7` for grid).
27	 */
28	
29	export type StatusSaveState = 'saved' | 'saving' | 'unsynced' | 'error';
30	export type StatusWsState = 'connected' | 'reconnecting' | 'offline';
31	
32	export interface StatusBarProps {
33	  level: { id: string; label: string };
34	  levels?: { id: string; label: string }[];
35	  onLevelChange?: (id: string) => void;
36	  toolLabel?: string | null;
37	  /** Snap mode group; toggling individual snaps lives here. */
38	  snapModes?: { id: string; label: string; on: boolean }[];
39	  onSnapToggle?: (id: string) => void;
40	  gridOn?: boolean;
41	  onGridToggle?: () => void;
42	  /** Live cursor model coords, in mm; null when off-canvas. */
43	  cursorMm?: { xMm: number; yMm: number } | null;
44	  /** Undo depth; clicking the cluster invokes undo / redo. */
45	  undoDepth?: number;
